<template><view class="page"><view class="title">消息中心</view><AppCard v-for="x in items" :key="x.id"><view>{{x.text||'[语音留言]'}}</view><view class="subtitle">{{x.deliveryStatus}}</view></AppCard><input class="input" v-model="text" placeholder="输入留言"/><button class="btn" @click="send">发送</button></view></template><script setup lang="ts">import{ref}from'vue';import{onLoad,onShow}from'@dcloudio/uni-app';import AppCard from'@/components/AppCard.vue';import{qingxierApi}from'@/services/api';const items=ref<any[]>([]),text=ref(''),relationId=ref('');onLoad((q:any)=>relationId.value=q.relationId||'');onShow(async()=>items.value=await qingxierApi.messages());async function send(){if(!relationId.value)return uni.showToast({title:'请从亲友圈进入',icon:'none'});await qingxierApi.sendMessage({relationId:relationId.value,messageType:'text',text:text.value});text.value='';items.value=await qingxierApi.messages();}</script>
